mapper.select:
select pred_id as predId, ID as id, claim_probability as claimProbability, claim_flag as claimFlag, risk_level as riskLevel, threshold_used as thresholdUsed, model_version as modelVersion, prediction_time as predictionTime from insur_pred
and pred_id = #{predId} and ID = #{id} and claim_flag = #{claimFlag} and risk_level = #{riskLevel}
order by pred_id desc
